291 static bool foldAnyOrAllBitsSetTrunc(Instruction &I) {
292   if (!I.getType()->isIntOrIntVectorTy(1))
293     return false;
294 
295   bool MatchAllBitsSet;
296   if (match(&I, m_Trunc(m_OneUse(m_And(m_Value(), m_Value())))))
297     MatchAllBitsSet = true;
298   else if (match(&I, m_Trunc(m_OneUse(m_Or(m_Value(), m_Value())))))
299     MatchAllBitsSet = false;
300   else
301     return false;
302   Value *X = I.getOperand(0);
303 
304   MaskOps MOps(X->getType()->getScalarSizeInBits(), MatchAllBitsSet);
305   if (!matchAndOrChain(X, MOps))
306     return false;
307 
308   // The pattern was found. Create a masked compare that replaces all of the
309   // shift and logic ops.
310   IRBuilder<> Builder(&I);
311   Constant *Mask = ConstantInt::get(X->getType(), MOps.Mask);
312   Value *And = Builder.CreateAnd(MOps.Root, Mask);
313   Value *Cmp = MatchAllBitsSet ? Builder.CreateICmpEQ(And, Mask)
314                                : Builder.CreateIsNotNull(And);
315   I.replaceAllUsesWith(Cmp);
316   ++NumAnyOrAllBitsSet;
317   return true;
