320 // Try to recognize below function as popcount intrinsic.
321 // This is the "best" algorithm from
322 // http://graphics.stanford.edu/~seander/bithacks.html#CountBitsSetParallel
323 // Also used in TargetLowering::expandCTPOP().
324 //
325 // int popcount(unsigned int i) {
326 //   i = i - ((i >> 1) & 0x55555555);
327 //   i = (i & 0x33333333) + ((i >> 2) & 0x33333333);
328 //   i = ((i + (i >> 4)) & 0x0F0F0F0F);
329 //   return (i * 0x01010101) >> 24;
330 // }
331 static bool tryToRecognizePopCount(Instruction &I) {
332   if (I.getOpcode() != Instruction::LShr)
333     return false;
334 
335   Type *Ty = I.getType();
336   if (!Ty->isIntOrIntVectorTy())
337     return false;
338 
339   unsigned Len = Ty->getScalarSizeInBits();
340   // FIXME: fix Len == 8 and other irregular type lengths.
341   if (!(Len <= 128 && Len > 8 && Len % 8 == 0))
342     return false;
343 
344   APInt Mask55 = APInt::getSplat(Len, APInt(8, 0x55));
345   APInt Mask33 = APInt::getSplat(Len, APInt(8, 0x33));
346   APInt Mask0F = APInt::getSplat(Len, APInt(8, 0x0F));
347   APInt Mask01 = APInt::getSplat(Len, APInt(8, 0x01));
348   APInt MaskShift = APInt(Len, Len - 8);
349 
350   Value *Op0 = I.getOperand(0);
351   Value *Op1 = I.getOperand(1);
352   Value *MulOp0;
353   // Matching "(i * 0x01010101...) >> 24".
354   if ((match(Op0, m_Mul(m_Value(MulOp0), m_SpecificInt(Mask01)))) &&
355       match(Op1, m_SpecificInt(MaskShift))) {
356     Value *ShiftOp0;
357     // Matching "((i + (i >> 4)) & 0x0F0F0F0F...)".
358     if (match(MulOp0, m_And(m_c_Add(m_LShr(m_Value(ShiftOp0), m_SpecificInt(4)),
359                                     m_Deferred(ShiftOp0)),
360                             m_SpecificInt(Mask0F)))) {
361       Value *AndOp0;
362       // Matching "(i & 0x33333333...) + ((i >> 2) & 0x33333333...)".
363       if (match(ShiftOp0,
364                 m_c_Add(m_And(m_Value(AndOp0), m_SpecificInt(Mask33)),
365                         m_And(m_LShr(m_Deferred(AndOp0), m_SpecificInt(2)),
366                               m_SpecificInt(Mask33))))) {
367         Value *Root, *SubOp1;
368         // Matching "i - ((i >> 1) & 0x55555555...)".
369         const APInt *AndMask;
370         if (match(AndOp0, m_Sub(m_Value(Root), m_Value(SubOp1))) &&
371             match(SubOp1, m_And(m_LShr(m_Specific(Root), m_SpecificInt(1)),
372                                 m_APInt(AndMask)))) {
373           auto CheckAndMask = [&]() {
374             if (*AndMask == Mask55)
375               return true;
376 
377             // Exact match failed, see if any bits are known to be 0 where we
378             // expect a 1 in the mask.
379             if (!AndMask->isSubsetOf(Mask55))
380               return false;
381 
382             APInt NeededMask = Mask55 & ~*AndMask;
383             return MaskedValueIsZero(cast<Instruction>(SubOp1)->getOperand(0),
384                                      NeededMask,
385                                      SimplifyQuery(I.getDataLayout()));
386           };
387 
388           if (CheckAndMask()) {
389             LLVM_DEBUG(dbgs() << "Recognized popcount intrinsic\n");
390             IRBuilder<> Builder(&I);
391             I.replaceAllUsesWith(
392                 Builder.CreateIntrinsic(Intrinsic::ctpop, I.getType(), {Root}));
393             ++NumPopCountRecognized;
394             return true;
395           }
396         }
397       }
398     }
399   }
400 
401   return false;
402 }
